SELECT , (6371 * acos(cos(radians(#{latitude})) * cos(radians(latitude)) * cos(radians(longitude) - radians(#{longitude})) + sin(radians(#{latitude})) * sin(radians(latitude)))) AS distance FROM post WHERE status = #{status} AND longitude IS NOT NULL AND latitude IS NOT NULL AND (6371 * acos(cos(radians(#{latitude})) * cos(radians(latitude)) * cos(radians(longitude) - radians(#{longitude})) + sin(radians(#{latitude})) * sin(radians(latitude)))) <= #{radius}
AND category_id = #{categoryId}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY is_top DESC, distance ASC, publish_time DESC LIMIT #{offset}, #{limit}

