mapper.update:
UPDATE post
category_id = #{categoryId}, title = #{title}, content = #{content}, image_urls = #{imageUrls,typeHandler=cn.edu.ccst.communitysocialmain.typehandler.DelimitedStringListTypeHandler}, status = #{status}, longitude = #{longitude}, latitude = #{latitude}, is_anonymous = #{isAnonymous}, is_top = #{isTop}, reviewer_id = #{reviewerId}, review_time = #{reviewTime}, review_remark = #{reviewRemark}, price = #{price}, transaction_mode = #{transactionMode}, contact_info = #{contactInfo},
WHERE post_id = #{postId}

UPDATE post
SET status = #{status}, 
  review_time = NOW(),
  reviewer_id = #{reviewerId}
WHERE post_id = #{postId}

UPDATE post
SET view_count = view_count + 1
WHERE post_id = #{postId}

UPDATE post
SET like_count = like_count + 1
WHERE post_id = #{postId}

UPDATE post
SET comment_count = comment_count + 1
WHERE post_id = #{postId}

UPDATE post
SET collect_count = collect_count + 1
WHERE post_id = #{postId}

UPDATE post
SET status = 0
WHERE post_id = #{postId}

mapper.select:
SELECT p.post_id, p.user_id, p.category_id, p.title, p.content, p.image_urls, p.status, p.longitude, p.latitude,
       p.view_count, p.like_count, p.comment_count, p.collect_count, p.is_anonymous,
       p.publish_time, p.reviewer_id, p.review_time, p.review_remark,
       p.price, p.transaction_mode, p.contact_info
FROM post p
INNER JOIN user u ON p.user_id = u.user_id
WHERE u.community = #{community} 
  AND p.category_id = #{categoryId}

  AND p.status = #{status}

ORDER BY p.is_top DESC, p.publish_time DESC
LIMIT #{offset}, #{limit}

SELECT p.post_id, p.user_id, p.category_id, p.title, p.content, p.image_urls, p.status, p.longitude, p.latitude,
       p.view_count, p.like_count, p.comment_count, p.collect_count, p.is_anonymous,
       p.publish_time, p.reviewer_id, p.review_time, p.review_remark,
       p.price, p.transaction_mode, p.contact_info
FROM post p
INNER JOIN user u ON p.user_id = u.user_id
WHERE u.community = #{community}
  AND p.status = #{status}

  AND p.category_id = #{categoryId}


  AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY p.is_top DESC, p.publish_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) 
FROM post p
INNER JOIN user u ON p.user_id = u.user_id
WHERE u.community = #{community}
  AND p.publish_time BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) 
FROM post p
INNER JOIN user u ON p.user_id = u.user_id
WHERE u.community = #{community}
  AND p.category_id = #{categoryId}
  AND p.status = 2
